import{_ as t,o,c as n,a2 as a}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"Epic: Plugin — Console","description":"","frontmatter":{},"headers":[],"relativePath":"epics/plugin-console.md","filePath":"epics/plugin-console.md"}'),i={name:"epics/plugin-console.md"};function l(s,e,r,d,c,p){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="epic-plugin-—-console" tabindex="-1">Epic: Plugin — Console <a class="header-anchor" href="#epic-plugin-—-console" aria-label="Permalink to &quot;Epic: Plugin — Console&quot;">​</a></h1><blockquote><p>The admin control plane — user management, plugin management, tenant settings, system health, and operator tooling.</p></blockquote><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>✅ Complete</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Console is a <code>type: platform</code>, <code>adminOnly</code> plugin that ships with Sovereign. It gives <code>platform:admin</code> and <code>platform:owner</code> users a unified control surface: manage users and invites, enable/disable plugins, configure tenant settings and root plugin, inspect system health, manage instance identity/branding, manage entitlements, and view the platform-wide activity feed. Console also renders install/remove UX for community plugins (two-step server-side flow: manifest preview → confirm).</p><h2 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h2><h4 id="✅-13-1-—-console-plugin-scaffold" tabindex="-1">✅ 13.1 — Console plugin scaffold <a class="header-anchor" href="#✅-13-1-—-console-plugin-scaffold" aria-label="Permalink to &quot;✅ 13.1 — Console plugin scaffold&quot;">​</a></h4><p><strong>Goal:</strong> Console plugin directory structure, manifest, and basic routing wired into the runtime via the generate script.</p><p><strong>Deliverables:</strong></p><ul><li><code>plugins/console/manifest.json</code> — type: <code>platform</code>, runtime: <code>native</code>, routePrefix: <code>/console</code>, adminOnly: true, shell: <code>default</code>, icon: <code>icon.svg</code></li><li><code>plugins/console/icon.svg</code> — Console icon, rendered by the shell in the sidebar bottom section (admin only)</li><li><code>plugins/console/app/layout.tsx</code> — console shell layout</li><li><code>plugins/console/app/page.tsx</code> — console home (empty, links to sub-sections)</li><li><code>plugins/console/db/schema.ts</code> — no tables yet (console reads platform tables)</li><li><code>plugins/console/package.json</code></li><li>Running <code>pnpm generate</code> wires console into the runtime</li></ul><p><strong>SRS reference:</strong> 3.5 Plugin System, 4.4 Functional Requirements — Console, PLT-03</p><p><strong>Review checklist:</strong></p><ul><li><code>/console</code> returns 403 for <code>platform:user</code>, accessible for <code>platform:admin</code></li><li>Generate script correctly picks up console manifest</li><li>Console appears in launcher for admin users only</li></ul><hr><h4 id="✅-13-2-—-console-user-management" tabindex="-1">✅ 13.2 — Console: user management <a class="header-anchor" href="#✅-13-2-—-console-user-management" aria-label="Permalink to &quot;✅ 13.2 — Console: user management&quot;">​</a></h4><p><strong>Goal:</strong> User list, invite, role change, and deactivate/reactivate.</p><p><strong>Deliverables:</strong></p><ul><li><code>plugins/console/app/users/page.tsx</code> — paginated user list: name, email, role, status, join date</li><li><code>plugins/console/app/users/invite/page.tsx</code> — invite form: generates invite token, sends email via <code>sdk.mailer</code></li><li>Role change and deactivate/reactivate as server actions</li><li>SDK <code>auth</code> and <code>mailer</code> real implementations wired in this task as a prerequisite for Console to function. <code>db</code> and <code>platform</code> implementations remain as stubs and are completed in Task 0.5.05.</li></ul><p><strong>SRS reference:</strong> CON-02, CON-03, CON-04, CON-05</p><p><strong>Review checklist:</strong></p><ul><li>User list shows all users with correct data</li><li>Invite email sends (or logs no-op) when SMTP unconfigured</li><li>Role change persists correctly</li><li>Deactivated user cannot log in</li></ul><hr><h4 id="✅-13-3-—-console-plugin-management" tabindex="-1">✅ 13.3 — Console: plugin management <a class="header-anchor" href="#✅-13-3-—-console-plugin-management" aria-label="Permalink to &quot;✅ 13.3 — Console: plugin management&quot;">​</a></h4><p><strong>Goal:</strong> Installed plugin list with enable/disable toggle.</p><p><strong>Deliverables:</strong></p><ul><li><code>plugins/console/app/plugins/page.tsx</code> — list of installed plugins from registry: name, version, type, status</li><li>Enable/disable toggle as server action — writes to a <code>plugin_status</code> table in platform db</li><li>Runtime middleware respects disabled status — returns 404 for disabled plugin routes</li><li>Disabled plugins hidden from launcher</li></ul><p><strong>SRS reference:</strong> CON-06, CON-07, PLT-04</p><p><strong>Review checklist:</strong></p><ul><li>Disabling a plugin blocks its routes immediately (no rebuild required)</li><li>Disabled plugin disappears from launcher</li><li>Re-enabling restores access</li></ul><hr><h4 id="✅-13-4-—-console-tenant-settings-system-health-and-root-plugin-config" tabindex="-1">✅ 13.4 — Console: tenant settings, system health, and root plugin config <a class="header-anchor" href="#✅-13-4-—-console-tenant-settings-system-health-and-root-plugin-config" aria-label="Permalink to &quot;✅ 13.4 — Console: tenant settings, system health, and root plugin config&quot;">​</a></h4><p><strong>Goal:</strong> Tenant name configuration, invite-only toggle, system health dashboard, and admin-configurable root plugin.</p><p><strong>Deliverables:</strong></p><ul><li><code>platform_settings</code> table added to <code>packages/db</code> schema (<code>src/schema/platform.ts</code>): <ul><li>Columns: <code>key</code> (string), <code>value</code> (string), <code>tenant_id</code> (string), <code>updated_at</code> (timestamp)</li><li>PK: <code>(key, tenant_id)</code></li><li>Initial row seeded on first run: <code>key = &#39;root_plugin_id&#39;</code>, <code>value = &#39;fs.sovereign.launcher&#39;</code></li></ul></li><li><code>plugins/console/app/settings/page.tsx</code> — three settings in one page: <ul><li>Tenant name field (CON-08) — writes to <code>tenants</code> table</li><li>Invite-only toggle (CON-10) — writes to <code>tenants</code> table, auth server reads it at registration</li><li>Root plugin selector (CON-11) — dropdown listing all installed, enabled, non-<code>adminOnly</code> plugins; writes <code>root_plugin_id</code> to <code>platform_settings</code>; change takes effect immediately without restart</li></ul></li><li><code>plugins/console/app/health/page.tsx</code> — runtime version, database type + connection status, auth server status, disk usage (CON-09)</li><li><code>runtime/app/(platform)/page.tsx</code> updated — reads <code>root_plugin_id</code> from <code>platform_settings</code> and redirects to that plugin&#39;s <code>routePrefix</code> (default: <code>/launcher</code>)</li><li>Tenant name stored in <code>tenants</code> table, exposed via <code>sdk.platform.getConfig()</code></li></ul><p><strong>SRS reference:</strong> CON-08, CON-09, CON-10, CON-11, PLT-06, PLT-14, PLT-15</p><p><strong>Review checklist:</strong></p><ul><li>Tenant name change reflects in <code>sdk.platform.getConfig()</code> immediately</li><li>Health page shows accurate database type (SQLite vs Postgres)</li><li>Invite-only toggle takes effect on next registration attempt without restart</li><li>Changing root plugin updates <code>platform_settings</code>; navigating to <code>/</code> immediately loads the newly configured root plugin without restart</li><li>When the root plugin is not the Launcher, the Launcher appears in the sidebar middle section as a regular icon linking to <code>/launcher</code> (PLT-12)</li><li><code>platform_settings</code> table present in migration; <code>root_plugin_id</code> seeded on first run</li></ul><hr><p>Subsequent tasks added Console sections as part of other epics:</p><table tabindex="0"><thead><tr><th>Task</th><th>Feature added to Console</th><th>Primary epic</th></tr></thead><tbody><tr><td>0.5.11</td><td>Data grants oversight (<code>/console/data-grants</code>)</td><td><a href="./platform-shell.html">Platform Shell</a></td></tr><tr><td>0.5.13</td><td>Activity feed (<code>/console/activity</code>)</td><td><a href="./activity-logs.html">Activity Logs</a></td></tr><tr><td>0.6.0</td><td>Role &amp; capability assignment UI</td><td><a href="./users-auth.html">Users &amp; Auth</a></td></tr><tr><td>0.8.0</td><td>Entitlement oversight, manual payment confirmation, Ed25519 key management</td><td><a href="./monetization.html">Monetization</a></td></tr><tr><td>0.8.3</td><td>Richer <code>/api/admin/health</code> response</td><td><a href="./platform-shell.html">Platform Shell</a></td></tr><tr><td>0.8.4</td><td>Instance identity / branding section</td><td><a href="./theming.html">Theming</a></td></tr><tr><td>9.9</td><td>Email Templates section</td><td><a href="./theming.html">Theming</a></td></tr><tr><td>1.7</td><td>Admin delete user action</td><td><a href="./users-auth.html">Users &amp; Auth</a></td></tr></tbody></table><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="./../plugins/console.html">docs/plugins/console.md</a> (if it exists)</li><li><a href="./../plugin-development.html">plugin-development.md</a></li></ul>',43)])])}const m=t(i,[["render",l]]);export{g as __pageData,m as default};
